/**
 * SMS notification channel.
 *
 * Handles delivery of notifications via SMS. Currently stores sent
 * messages in memory for testing/demo purposes. In production, this would
 * integrate with an SMS gateway (e.g. Twilio, SNS).
 */

import type { NotificationSendEvent } from '../../events/event-types.js';
import { Logger } from '../../utils/logger.js';
import type { NotificationChannel } from './notification-channel.js';

export interface SentSms {
  recipient: string;
  body: string;
  sentAt: Date;
}

export class SmsNotificationChannel implements NotificationChannel {
  readonly name = 'sms';
  private logger = new Logger('SmsChannel');
  private sentMessages: SentSms[] = [];

  /**
   * Send a notification via SMS.
   */
  send(event: NotificationSendEvent): void {
    const sms: SentSms = {
      recipient: event.recipient,
      body: event.body,
      sentAt: new Date(),
    };
    this.sentMessages.push(sms);
    this.logger.info(`SMS sent to ${event.recipient}: ${event.subject}`);
  }

  /**
   * Get all sent SMS messages. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

/**
 * Webhook notification channel.
 *
 * Handles delivery of notifications via HTTP webhooks. Currently stores
 * delivered payloads in memory for testing/demo purposes. In production,
 * this would POST JSON payloads to configured webhook URLs.
 */

import type { NotificationSendEvent } from '../../events/event-types.js';
import { Logger } from '../../utils/logger.js';
import type { NotificationChannel } from './notification-channel.js';

export interface WebhookPayload {
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class WebhookNotificationChannel implements NotificationChannel {
  readonly name = 'webhook';
  private logger = new Logger('WebhookChannel');
  private deliveredPayloads: WebhookPayload[] = [];

  /**
   * Send a notification via webhook.
   */
  send(event: NotificationSendEvent): void {
    const payload: WebhookPayload = {
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.deliveredPayloads.push(payload);
    this.logger.info(`Webhook delivered to ${event.recipient}: ${event.subject}`);
  }

  /**
   * Get all delivered webhook payloads. Useful for testing.
   */
  getDeliveredPayloads(): WebhookPayload[] {
    return [...this.deliveredPayloads];
  }

  /**
   * Clear delivered payloads. Useful for testing.
   */
  clearDeliveredPayloads(): void {
    this.deliveredPayloads = [];
  }
}
